  ('optometrist-moex-01884', 'optometrist', 'optometrist-moex-109-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關硬式隱形眼鏡偏位之情形，下列敘述何者正確？①弧度太陡較易偏位  ②順性散光較易偏上位  ③逆性', '["加大鏡片可改善偏位情形  ⑤鏡片邊挑（edgeclearance）太大易偏位", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:50+00:00", "source_pdf_sha1": "785b179c1fff", "answer_pdf_sha1": "89b8a3c03213", "source_family": "moex-gov-tw", "moex": {"exam_code": "109060", "c": "401", "s": "0804", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "109", "exam_name": "109年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 15, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01885', 'optometrist', 'optometrist-moex-109-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '戴上硬式隱形鏡片後弧半徑BOZR8.00mm，度數-3.00DS，檢查後發現，鏡片中心定位偏移外側一些， 但有包覆瞳孔，螢光染色型態（fluoreceinpatterns）較平約 0.1mm，插片驗光-1.00DS視力1.0，若訂片 BOZR7.90mm，度數應訂：', '["-4.00DS", "-4.50DS", "-3.50DS", "-3.00DS"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:50+00:00", "source_pdf_sha1": "785b179c1fff", "answer_pdf_sha1": "89b8a3c03213", "source_family": "moex-gov-tw", "moex": {"exam_code": "109060", "c": "401", "s": "0804", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "109", "exam_name": "109年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01886', 'optometrist', 'optometrist-moex-109-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '角膜弧度測量為43.00D@180/44.00D@090，眼鏡處方為-2.00DS/-0.50DC×180，如果配戴硬式透氧隱形眼 鏡，會有多少殘餘散光？', '["-0.50DC×090", "-0.50DC×180", "-1.50DC×090", "-1.50DC×180"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:50+00:00", "source_pdf_sha1": "785b179c1fff", "answer_pdf_sha1": "89b8a3c03213", "source_family": "moex-gov-tw", "moex": {"exam_code": "109060", "c": "401", "s": "0804", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "109", "exam_name": "109年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01887', 'optometrist', 'optometrist-moex-109-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關細隙燈的檢查，下列敘述何者錯誤？', '["光學切面照明法（opticsection），可以觀察角膜疤痕的深度", "間接照射的鏡面反射法（specularreflection），可以觀察角膜內皮細胞", "背面反射照明法（retroillumination），是觀察角膜上皮微囊腫（epithelialmicrocysts）的好方法", "角鞏膜緣散射法（scleroticscatter），屬於間接照射法"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:50+00:00", "source_pdf_sha1": "785b179c1fff", "answer_pdf_sha1": "89b8a3c03213", "source_family": "moex-gov-tw", "moex": {"exam_code": "109060", "c": "401", "s": "0804", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "109", "exam_name": "109年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01888', 'optometrist', 'optometrist-moex-109-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '下圖為有關硬式隱形眼鏡驗配的螢光染色觀察，下列敘述何者錯誤？', '["試戴者可能有角膜散光", "角膜弧度可能為8.00mm@176,7.25mm@086", "如果沒有晶體散光，建議使用散光隱形眼鏡", "如果中心定位不穩定，常見往左右偏移"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:50+00:00", "source_pdf_sha1": "785b179c1fff", "answer_pdf_sha1": "89b8a3c03213", "source_family": "moex-gov-tw", "moex": {"exam_code": "109060", "c": "401", "s": "0804", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "109", "exam_name": "109年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01889', 'optometrist', 'optometrist-moex-109-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關配戴軟式隱形眼鏡引起的併發症角膜上皮層脫落（reducedepithelialadhesionsigns）之敘述，下列何 者最正確？', '["常見於使用高透氧矽水膠的鏡片配戴者", "角膜缺氧引起角膜上皮細胞厚度變薄、半胞橋小體（hemidesmosome）密度減少，以致上皮細胞與其基 底膜脫離", "處理方法為選用隱形眼鏡鏡片中心較薄的低含水量、低透氧性的軟式隱形眼鏡，就可避免損傷角膜上皮", "與隱形眼鏡材料的彈性模數（modulusofelasticity）有直接相關"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:50+00:00", "source_pdf_sha1": "785b179c1fff", "answer_pdf_sha1": "89b8a3c03213", "source_family": "moex-gov-tw", "moex": {"exam_code": "109060", "c": "401", "s": "0804", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "109", "exam_name": "109年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01890', 'optometrist', 'optometrist-moex-109-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關細隙燈檢查角膜水腫之敘述，下列何者錯誤？', '["角膜基質水腫（stromaedema）程度小於5%時一般無症狀，屈光度也不會有改變", "發生在角膜基質層（stroma）及德士密氏膜（Descemet''smembrance）以橫向呈現", "條紋（striate）在基質層，線條呈現不分歧", "褶痕（fold）水腫程度接近10%，用鏡面反射法可在角膜內皮層看到長直的線"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:50+00:00", "source_pdf_sha1": "785b179c1fff", "answer_pdf_sha1": "89b8a3c03213", "source_family": "moex-gov-tw", "moex": {"exam_code": "109060", "c": "401", "s": "0804", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "109", "exam_name": "109年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01891', 'optometrist', 'optometrist-moex-109-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '配戴硬式隱形眼鏡基弧過緊不會造成：', '["過多的螢光染色劑積水在鏡片中間", "鏡片外圍壓迫在角膜上", "鏡片下面的新陳代謝殘留物無法排出", "角膜中心曲率半徑變長"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:50+00:00", "source_pdf_sha1": "785b179c1fff", "answer_pdf_sha1": "89b8a3c03213", "source_family": "moex-gov-tw", "moex": {"exam_code": "109060", "c": "401", "s": "0804", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "109", "exam_name": "109年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
